// Validation utilities (simulated module)
const validate = {
  required: (value: string): string | null =>
    value.trim() ? null : "This field is required",

  email: (value: string): string | null =>
    /^[^@]+@[^@]+\.[^@]+$/.test(value) ? null : "Invalid email address",

  minLength: (min: number) => (value: string): string | null =>
    value.length >= min ? null : `Must be at least ${min} characters`,

  maxLength: (max: number) => (value: string): string | null =>
    value.length <= max ? null : `Must be at most ${max} characters`,
};

const fields = [
  { name: "email",    value: "alice@example.com", validators: [validate.required, validate.email] },
  { name: "password", value: "abc",               validators: [validate.required, validate.minLength(8)] },
  { name: "bio",      value: "Hello world",        validators: [validate.maxLength(10)] },
];

for (const { name, value, validators } of fields) {
  const error = validators.map(v => v(value)).find(e => e !== null);
  console.log(`${name}: ${error ?? "valid"}`);
}

// Simulating dynamic import (sync in this sandbox)
async function loadFormatter(format: "json" | "csv" | "xml"): Promise<{ format: (data: Record<string, unknown>[]) => string }> {
  // In real code: return await import(`./formatters/${format}`);
  // Simulated:
  const formatters = {
    json: { format: (d: Record<string,unknown>[]) => JSON.stringify(d, null, 2) },
    csv:  { format: (d: Record<string,unknown>[]) => {
      const headers = Object.keys(d[0]).join(",");
      const rows = d.map(r => Object.values(r).join(","));
      return [headers, ...rows].join("\n");
    }},
    xml: { format: (d: Record<string,unknown>[]) =>
      d.map(r => `<record>${Object.entries(r).map(([k,v])=>`<${k}>${v}</${k}>`).join("")}</record>`).join("\n")
    },
  };
  return formatters[format];
}

async function exportData(format: "json" | "csv" | "xml") {
  const data = [{ id: 1, name: "Alice" }, { id: 2, name: "Bob" }];
  const { format: fmt } = await loadFormatter(format);
  console.log(`=== ${format.toUpperCase()} ===`);
  console.log(fmt(data));
}

(async () => { await exportData("csv"); })();

