// Determine runtime environment
const isNode = typeof process !== "undefined" && process.versions?.node;
const isBrowser = typeof window !== "undefined";

function getStorageImplementation(): {
  get(key: string): string | null;
  set(key: string, value: string): void;
  clear(): void;
} {
  // In Node.js, use an in-memory store
  const memStore = new Map<string, string>();
  return {
    get: (key) => memStore.get(key) ?? null,
    set: (key, value) => { memStore.set(key, value); },
    clear: () => memStore.clear(),
  };
  // In a browser, you'd return localStorage:
  // return window.localStorage;
}

const storage = getStorageImplementation();
storage.set("user", JSON.stringify({ id: 1, name: "Alice" }));
storage.set("lang", "typescript");

const user = JSON.parse(storage.get("user") ?? "{}");
console.log(`User: ${user.name}`);
console.log(`Lang: ${storage.get("lang")}`);
console.log(`Missing: ${storage.get("missing") ?? "not found"}`);

// These patterns would cause errors in strict mode:

// 1. strictNullChecks — variables can't be null/undefined unless declared so
function getUsername(user: { name: string } | null): string {
  // Without strictNullChecks: user.name would compile
  // With strictNullChecks: must handle null
  return user?.name ?? "Guest";
}

// 2. strictFunctionTypes — more precise function type checking
type Handler = (event: MouseEvent) => void;
const clickHandler: Handler = (e) => {
  // e is MouseEvent — not just Event
  console.log(`Click at ${e.clientX}, ${e.clientY}`);
};

// 3. noImplicitAny — all parameters must be typed
function process(data: string[]): string {
  // Without this rule: data could be `any[]` without annotation
  return data.join(", ");
}

